// ───────────────────────────────────────────────
// ระบบ overlay: ฐานลูกค้า 2,870 รายอยู่ในไฟล์นี้ (window.SAMPLE_CUSTOMERS)
// localStorage เก็บเฉพาะส่วนที่ผู้ใช้ เพิ่ม/แก้ไข/ลบ (ใช้พื้นที่น้อย ไม่ชน quota)
function loadCustomers() {
  let overlay = { added: [], updated: {}, deleted: [] };
  try {
    const raw = localStorage.getItem("CUSTOMERS_OVERLAY");
    if (raw) overlay = { added: [], updated: {}, deleted: [], ...JSON.parse(raw) };
  } catch (e) {}
  const deleted = new Set(overlay.deleted);
  const base = SAMPLE_CUSTOMERS
    .filter(c => !deleted.has(c.id))
    .map(c => overlay.updated[c.id] ? { ...c, ...overlay.updated[c.id] } : c);
  return [...base, ...overlay.added];
}

function saveCustomers(newList) {
  const baseById = new Map(SAMPLE_CUSTOMERS.map(c => [c.id, c]));
  const overlay = { added: [], updated: {}, deleted: [] };
  const newIds = new Set();
  for (const c of newList) {
    newIds.add(c.id);
    const base = baseById.get(c.id);
    if (!base) overlay.added.push(c);
    else if (JSON.stringify(base) !== JSON.stringify(c)) overlay.updated[c.id] = c;
  }
  for (const id of baseById.keys()) {
    if (!newIds.has(id)) overlay.deleted.push(id);
  }
  try {
    localStorage.setItem("CUSTOMERS_OVERLAY", JSON.stringify(overlay));
    return true;
  } catch (e) {
    console.warn("ไม่สามารถบันทึก overlay ลูกค้า:", e);
    return false;
  }
}

Object.assign(window, { SAMPLE_CUSTOMERS, CUSTOMER_DATA_VERSION, loadCustomers, saveCustomers });
